<template>
  <div id="Create-Call-Abroad">
    <section class="Create-call-abroad">
      <v-skeleton-loader class="mx-auto" type="form"></v-skeleton-loader>
      <div class="header contact-header">
        <h1>{{ $t("Call-Abroad.Edit.title") }}</h1>
      </div>
      <div class="create-contents">
        <div class="form">
          <v-form lazy-validation ref="form" v-model="isValid">
            <v-row>
              <v-col cols="12">
                <v-text-field
                  :label="$t('Call-Abroad.form.countrylao')"
                  outlined
                  required
                  :rules="[
                    $myValidator.SimpleValidate($t('Validate.required')),
                  ]"
                  :placeholder="$t('Call-Abroad.form.lao')"
                  v-model="DataCall.country_la"
                ></v-text-field>
              </v-col>
              <v-col cols="12">
                <v-text-field
                  :label="$t('Call-Abroad.form.countryeng')"
                  outlined
                  required
                  :rules="[
                    $myValidator.SimpleValidate($t('Validate.required')),
                  ]"
                  :placeholder="$t('Call-Abroad.form.english')"
                  v-model="DataCall.country_eng"
                ></v-text-field>
              </v-col>
              <v-col cols="6">
                <v-text-field
                  :label="$t('Call-Abroad.form.countryCode')"
                  outlined
                  required
                  :rules="[
                    $myValidator.SelectValidate($t('Validate.required')),
                  ]"
                  v-model="DataCall.countryCode"
                ></v-text-field>
              </v-col>
              <v-col cols="6">
                <v-select
                  :items="ZoneItems"
                  item-text="zoneName_la"
                  item-value="id"
                  v-model="DataCall.zone_id"
                  :label="$t('Call-Abroad.form.zone')"
                  outlined
                  required
                  :rules="[
                    $myValidator.SelectValidate($t('Validate.required')),
                  ]"
                ></v-select>
              </v-col>
              <v-col cols="12">
                <v-text-field
                  :label="$t('Call-Abroad.form.price')"
                  outlined
                  required
                  :rules="[
                    $myValidator.SelectValidate($t('Validate.required')),
                  ]"
                  type="number"
                  suffix="LAK"
                  v-model="DataCall.price_minute"
                ></v-text-field>
              </v-col>
            </v-row>
          </v-form>
          <div class="text-right">
            <v-btn @click.prevent="ResetForm" color="success" text>{{
              $t("Call-Abroad.options.cancel")
            }}</v-btn>
            <v-btn
              @click.prevent="SubmitCallAbroad"
              :disabled="!isValid"
              :loading="isLoading"
              class="btn btn-create ml-3"
              >{{ $t("Call-Abroad.options.save") }}</v-btn
            >
          </div>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
export default {
  name: "TplusWebAdminCreate",

  data() {
    return {
      ZoneItems: [],
      ItemSelected: null,
      isValid: false,
      isLoading:false,
      DataCall: {
        country_la: null,
        country_eng: null,
        countryCode: null,
        zone_id: null,
        price_minute: null,
      },
    };
  },

  mounted() {},

  methods: {
    SubmitCallAbroad() {
      if(this.$refs.form.validate()){
        this.onEditDataCall();
      }
    },
    ResetForm() {
      this.$refs.form.reset();
      this.$router.back();
    },
    async onEditDataCall() {
      this.isLoading = true;
      await this.$axios
        .put(`internationCalls/${this.$route.params.id}`, {
          countryName_la: this.DataCall.country_la,
          countryName_en: this.DataCall.country_eng,
          code: this.DataCall.countryCode,
          zoneId: this.DataCall.zone_id,
          price_minute: this.DataCall.price_minute,
        })
        .then((res) => {
          if(res.status == 200){
             this.$store.dispatch({
              type: "action_Notifi_Success",
              message: this.$t("Notification.editDataSuccess"),
            });
            setTimeout(() => {
              window.location.reload();
            }, 300);
          }
           this.isLoading = false;
           this.$router.push({name:'call-abroad.index'})
        }).catch((error)=>{
           this.isLoading = false;
           setTimeout(() => {
              this.$store.dispatch({
                type: "action_Notifi_Error",
                message: `${error.response.data.error.message}`,
              });
            }, 300);
        });
    },
    async getDataCallById() {
      await this.$axios
        .get(`internationCalls/${this.$route.params.id}`, {
          headers: {
            content_language: "en",
          },
        })
        .then((res) => {
          if (res.status == 200) {
            const data = res.data.data;
            this.DataCall = {
              country_la: data.countryName_la,
              country_eng: data.countryName_en,
              countryCode: data.code,
              zone_id: data.Zones.id,
              price_minute: data.price_minute,
            };
          }
        })
        .catch((error) => {
          setTimeout(() => {
            this.$store.dispatch({
              type: "action_Notifi_Error",
              message: `${error.response.data.error.message}`,
            });
          }, 300);
        });
    },

    async getZones() {
      await this.$axios
        .get("zones")
        .then((res) => {
          if (res.status == 200) {
            this.ZoneItems = res.data.data;
          }
        })
        .catch((error) => {
          console.log(error);
        });
    },
  },

  created() {
    this.getDataCallById();
    this.getZones();
  },
};
</script>

